/**
 * Example seed prompts for the AI Brief Orchestrator.
 *
 * AUTOGENERATED — do not edit by hand. Source of truth lives in
 * `examples/campaigns/<slug>/seed-prompt.md` (the first fenced code
 * block of each file). Regenerate with:
 *
 *     REGEN_EXAMPLE_PROMPTS=1 npx vitest run __tests__/regen-example-prompts.test.ts
 *
 * The frontend `BriefGeneratorAI` component imports `EXAMPLE_SEEDS` to
 * power the "Load example" secondary button — picks one at random and
 * paste-fills the textarea. No API call, no LLM, no runtime FS read.
 */

export interface ExampleSeed {
  /** Folder name under examples/campaigns/ */
  slug: string;
  /** Stable id from brief.json campaign.id */
  campaignId: string;
  /** Human-readable name from brief.json campaign.name */
  campaignName: string;
  /** Paste-ready seed prompt — extracted from seed-prompt.md, ≤1000 chars */
  prompt: string;
}

