/**
 * Pick one example seed at random.
 *
 * Used by the "Load example" button. Pure function — pass `Math.random`
 * (or a seeded RNG in tests) so the picker stays deterministic when
 * needed.
 */
export function pickRandomSeed(rng: () => number = Math.random): ExampleSeed {
  if (EXAMPLE_SEEDS.length === 0) {
    throw new Error(
      "pickRandomSeed: EXAMPLE_SEEDS is empty — run the regen test to populate it."
    );
  }
  const i = Math.floor(rng() * EXAMPLE_SEEDS.length);
  // Non-null assertion is safe — i is bounded by the length check above.
  return EXAMPLE_SEEDS[i]!;
}
